from dataclasses import dataclass
from datetime import date, timedelta
from enum import Enum

class ConflictType(str, Enum):
    SCOPE = "scope"
    RISK_TOLERANCE = "risk_tolerance"
    RESOURCE = "resource"
    REQUIREMENTS = "requirements"
    ETHICAL = "ethical"

class EscalationLevel(str, Enum):
    L1 = "L1"
    L2 = "L2"
    L3 = "L3"
    L4 = "L4"

# SLA in calendar days for each level
SLA_DAYS = {EscalationLevel.L1: 2, EscalationLevel.L2: 7, EscalationLevel.L3: 14, EscalationLevel.L4: 30}

@dataclass
class ConflictRecord:
    id: str
    title: str
    conflict_type: ConflictType
    current_level: EscalationLevel
    escalated_at: date
    status: str  # open | resolved | deferred

    @property
    def sla_deadline(self) -> date:
        return self.escalated_at + timedelta(days=SLA_DAYS[self.current_level])

    @property
    def days_until_sla(self) -> int:
        return (self.sla_deadline - date.today()).days

    @property
    def sla_status(self) -> str:
        if self.days_until_sla < 0:
            return f"BREACHED ({abs(self.days_until_sla)}d overdue)"
        elif self.days_until_sla <= 1:
            return "URGENT (due today or tomorrow)"
        else:
            return f"OK ({self.days_until_sla}d remaining)"

def print_conflict_register(conflicts: list[ConflictRecord]) -> None:
    open_conflicts = [c for c in conflicts if c.status == "open"]
    breached = [c for c in open_conflicts if c.days_until_sla < 0]
    if breached:
        print("=== BREACHED SLAs ===")
        for c in breached:
            print(f"  [{c.id}] {c.title} | Level: {c.current_level} | {c.sla_status}")
        print()
    urgent = [c for c in open_conflicts if 0 <= c.days_until_sla <= 1]
    if urgent:
        print("=== URGENT (SLA due today/tomorrow) ===")
        for c in urgent:
            print(f"  [{c.id}] {c.title} | Level: {c.current_level}")
        print()
    healthy = [c for c in open_conflicts if c.days_until_sla > 1]
    print(f"=== OPEN CONFLICTS: {len(open_conflicts)} total ===")
    for c in healthy:
        print(f"  [{c.id}] {c.title} | {c.conflict_type} | Level: {c.current_level} | {c.sla_status}")

if __name__ == "__main__":
    register = [
        ConflictRecord("CDR-005", "Agent scope for payment approval", ConflictType.SCOPE, EscalationLevel.L1, date(2025, 10, 8), "open"),
        ConflictRecord("CDR-006", "Autonomous escalation threshold", ConflictType.ETHICAL, EscalationLevel.L3, date(2025, 9, 25), "open"),
        ConflictRecord("CDR-007", "Audit log retention", ConflictType.RISK_TOLERANCE, EscalationLevel.L3, date(2025, 9, 17), "resolved"),
    ]
    print_conflict_register(register)
